<?php include __DIR__.'/includes/header.php';
$slug=$_GET['slug']??''; $q=$db->prepare("SELECT * FROM courses WHERE slug=? AND status='published' LIMIT 1"); $q->execute([$slug]); $course=$q->fetch(); if(!$course){http_response_code(404); echo '<main class="container py-5"><h1>Course not found</h1></main>'; include __DIR__.'/includes/footer.php'; exit;}
$less=$db->prepare('SELECT * FROM lessons WHERE course_id=? ORDER BY sort_order'); $less->execute([$course['id']]); $lessons=$less->fetchAll();
?>
<section class="container py-5"><h1><?=e($course['title'])?></h1><p><?=e($course['full_description'])?></p><div class="row g-4"><div class="col-lg-8"><h3>Curriculum</h3><ul><?php foreach($lessons as $l):?><li><?=e($l['title'])?> (<?=e($l['duration_minutes'])?> mins)</li><?php endforeach;?></ul><h3>Who should enroll</h3><p>Law students, associates, junior advocates, legal researchers, and compliance teams seeking practical AI legal workflows.</p></div><div class="col-lg-4"><div class="card"><div class="card-body"><p><strong>Duration:</strong> <?=e($course['duration'])?></p><p><strong>Level:</strong> <?=e($course['level'])?></p><p><strong>Certificate:</strong> <?=$course['certificate_available']?'Yes':'No'?></p><p class="h5">₹<?=e($course['discounted_price']?:$course['price'])?></p><a class="btn btn-primary w-100" href="/student/enroll.php?course_id=<?=$course['id']?>">Enroll Now</a></div></div></div></div></section>
<?php include __DIR__.'/includes/footer.php'; ?>
